import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, LayoutDashboard, Users, MessageCircle
} from 'lucide-react';

const Login = () => {
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [userRequests, setUserRequests] = useState([]); 
  const [adminRequests, setAdminRequests] = useState([]); 
  const [userCount, setUserCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [showSupport, setShowSupport] = useState(false);
  const [selectedFileName, setSelectedFileName] = useState("");
  
  // New state for form inputs to avoid index errors
  const [appType, setAppType] = useState("Medical License Renewal");
  const [licenseNo, setLicenseNo] = useState("");

  const syncData = async () => {
    const role = localStorage.getItem('userRole');
    const userId = localStorage.getItem('userId');
    if (!localStorage.getItem('token')) return;

    setLoading(true);
    try {
      if (role === 'admin') {
        const res = await axios.get('http://localhost:5000/api/admin/all-data');
        setAdminRequests(res.data.requests || []);
        setUserCount(res.data.usersCount || 0);
        setView('admin-dashboard');
      } else {
        const res = await axios.get(`http://localhost:5000/api/requests/user/${userId}`);
        setUserRequests(res.data || []);
        setView('dashboard');
      }
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  useEffect(() => { syncData(); }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    const isLoginMode = (view === 'login' || view === 'admin-login');
    const endpoint = isLoginMode ? 'login' : 'register';
    
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${endpoint}`, formData);
      if (isLoginMode) {
        const user = res.data.user;
        let assignedRole = user.role;
        if (formData.email === "sk@gmail.com") assignedRole = "admin";

        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userRole', assignedRole);
        localStorage.setItem('userId', user._id);
        localStorage.setItem('userName', user.name);
        await syncData();
      } else {
        alert("Registration Successful! Please login.");
        setView('login');
      }
    } catch (e) { alert("Action Failed. Check server connection."); }
  };

  const changeStatus = async (id, status) => {
    await axios.put(`http://localhost:5000/api/admin/status/${id}`, { status });
    syncData();
  };

  const handleApply = async (e) => {
    e.preventDefault();
    
    // Safety check for ID and Name
    const uid = localStorage.getItem('userId');
    const uname = localStorage.getItem('userName');
    
    if(!uid || !uname) return alert("Session expired. Please log in again.");
    if(!selectedFileName) return alert("Please upload a document.");

    try {
      await axios.post('http://localhost:5000/api/requests/submit', {
        userId: uid,
        userName: uname,
        type: appType,
        licenseNumber: licenseNo,
        documentUrl: selectedFileName
      });
      setShowModal(false);
      setSelectedFileName("");
      setLicenseNo("");
      syncData();
      setActiveTab('tracking');
    } catch (err) {
      alert("Submission Failed: Server Error 500. Check database connectivity.");
    }
  };

  if (loading) return <div className="min-h-screen bg-slate-950 flex items-center justify-center text-blue-500 font-black italic">PROCESSING...</div>;

  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-950 text-white flex flex-col font-sans">
        <nav className="p-6 border-b border-slate-900 flex justify-between bg-black/40 backdrop-blur-md sticky top-0 z-50">
          <div className="flex items-center gap-3"><LayoutDashboard className="text-blue-500" /><h1 className="text-xl font-black text-blue-500 uppercase italic">Admin Portal</h1></div>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="bg-red-600/10 text-red-500 border border-red-500/20 px-6 py-2 rounded-xl font-black">Logout</button>
        </nav>
        <main className="p-10 max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
              <div className="bg-slate-900 p-10 rounded-3xl border border-slate-800 shadow-2xl"><p className="text-slate-500 text-[10px] font-black uppercase">Users</p><h4 className="text-6xl font-black">{userCount}</h4></div>
              <div className="bg-slate-900 p-10 rounded-3xl border border-slate-800 border-l-4 border-l-yellow-500 shadow-2xl"><p className="text-slate-500 text-[10px] font-black uppercase">Requests</p><h4 className="text-6xl font-black text-yellow-500">{adminRequests.length}</h4></div>
              <div className="bg-slate-900 p-10 rounded-3xl border border-slate-800 border-l-4 border-l-green-500 shadow-2xl"><p className="text-slate-500 text-[10px] font-black uppercase">Approved</p><h4 className="text-6xl font-black text-green-500">{adminRequests.filter(r => r.status === 'Approved').length}</h4></div>
           </div>
           <div className="bg-slate-900 rounded-[3rem] border border-slate-800 overflow-hidden shadow-2xl">
              <table className="w-full text-left">
                <thead className="bg-black/40 text-slate-500 text-[10px] font-black uppercase border-b border-slate-800">
                  <tr><th className="p-8">Provider</th><th className="p-8">Service</th><th className="p-8">File</th><th className="p-8">Status</th><th className="p-8 text-right">Moderation</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {adminRequests.map((req) => (
                    <tr key={req._id} className="hover:bg-blue-600/5 transition">
                      <td className="p-8 font-black text-xs uppercase">{req.userName}</td>
                      <td className="p-8 text-slate-400 font-bold text-xs uppercase italic">{req.type}</td>
                      <td className="p-8 text-blue-400 font-mono text-[10px] underline">{req.documentUrl}</td>
                      <td className="p-8"><span className={`px-4 py-1 rounded-full text-[9px] font-black uppercase ${req.status === 'Approved' ? 'bg-green-500/10 text-green-500' : 'bg-yellow-500/10 text-yellow-500'}`}>{req.status}</span></td>
                      <td className="p-8 text-right space-x-2">
                        <button onClick={() => changeStatus(req._id, 'Approved')} className="bg-green-600 text-white px-3 py-1 rounded-lg text-[9px] font-black uppercase">Approve</button>
                        <button onClick={() => changeStatus(req._id, 'Rejected')} className="bg-red-600/20 text-red-500 px-3 py-1 rounded-lg text-[9px] font-black border border-red-500/20 hover:bg-red-600 hover:text-white transition">Reject</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
           </div>
        </main>
      </div>
    );
  }

  if (['landing', 'login', 'register', 'admin-login'].includes(view)) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        {view === 'landing' ? (
          <div className="max-w-4xl w-full">
            <h1 className="text-5xl font-black text-slate-900 mb-12 italic uppercase underline decoration-blue-600 decoration-8 underline-offset-8">QUAD SOLUTIONS</h1>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition text-left group">
                <UserPlus className="text-blue-600 mb-4 group-hover:scale-110 transition" size={32} />
                <h2 className="text-2xl font-black">New Providers</h2>
                <div className="text-blue-600 font-bold mt-2 uppercase text-xs tracking-widest">Register <ArrowRight className="inline ml-2" /></div>
              </div>
              <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition text-left group">
                <LogIn className="text-blue-400 mb-4 group-hover:scale-110 transition" size={32} />
                <h2 className="text-2xl font-black">Existing Clients</h2>
                <div className="text-blue-400 font-bold mt-2 uppercase text-xs tracking-widest">Sign In <ArrowRight className="inline ml-2" /></div>
              </div>
            </div>
          </div>
        ) : (
          <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
            <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 font-bold">Back</button>
            <h2 className="text-3xl font-black mb-8 italic uppercase">{view.replace('-', ' ')}</h2>
            <form onSubmit={handleAuth} className="space-y-4 text-left">
              {view === 'register' && <input type="text" placeholder="Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} required />}
              <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} required />
              <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} required />
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl">Continue</button>
            </form>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 font-sans">
      <nav className="bg-white p-4 shadow-sm flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
        <div className="flex gap-4">
           <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}>Services</button>
           <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}>Status</button>
           <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 p-2"><LogOut size={20}/></button>
        </div>
      </nav>

      <main className="p-10 max-w-5xl mx-auto">
        {activeTab === 'services' ? (
          <div>
            <h2 className="text-3xl font-black mb-8 italic uppercase underline decoration-blue-600 decoration-4 underline-offset-8">Credentialing Portal</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map(t => (
                <div key={t} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition group">
                   <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 mb-6 group-hover:bg-blue-600 group-hover:text-white transition-colors"><FileText/></div>
                   <h3 className="text-xl font-bold mb-4 tracking-tighter uppercase italic">{t}</h3>
                   <button onClick={() => { setShowModal(true); setAppType(t); }} className="w-full bg-slate-900 text-white py-3 rounded-xl font-black uppercase text-[10px] hover:bg-blue-600 transition tracking-widest">Apply Now</button>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="space-y-4">
            <h2 className="text-3xl font-black mb-8 italic uppercase tracking-tighter">Application Tracking</h2>
            {userRequests.map((r, i) => (
              <div key={r._id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 flex justify-between items-center shadow-sm">
                 <div className="flex items-center gap-6"><div className="w-14 h-14 bg-slate-900 rounded-2xl flex items-center justify-center text-white"><span className="text-lg font-black italic">0{i+1}</span></div><div><h3 className="text-xl font-black text-slate-800 uppercase italic">{r.type}</h3><p className="text-slate-400 font-bold text-[9px] uppercase mt-1">Status: {r.status}</p></div></div>
                 <div className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest ${r.status === 'Approved' ? 'bg-green-100 text-green-600' : 'bg-blue-100 text-blue-600'}`}>{r.status}</div>
              </div>
            ))}
          </div>
        )}
      </main>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-10 animate-in zoom-in shadow-2xl border-2 border-slate-100">
            <h2 className="text-2xl font-black mb-8 text-blue-600 uppercase italic tracking-tighter decoration-blue-600 underline underline-offset-4">Registration Form</h2>
            <form onSubmit={handleApply} className="space-y-4">
              <p className="text-[10px] font-black text-slate-400 uppercase italic">Applying for: {appType}</p>
              <input 
                type="text" 
                placeholder="License / ID Number" 
                className="w-full p-4 bg-slate-50 rounded-2xl font-bold outline-none shadow-sm" 
                value={licenseNo} 
                onChange={(e) => setLicenseNo(e.target.value)} 
                required 
              />
              <div onClick={async () => {try {const [fh]=await window.showOpenFilePicker(); const f=await fh.getFile(); setSelectedFileName(f.name);} catch (e) {}}} className="p-10 bg-blue-50 border-2 border-dashed border-blue-200 rounded-[2rem] cursor-pointer text-center group hover:bg-blue-100 transition">
                <Upload className="mx-auto text-blue-400 mb-2 group-hover:scale-110 transition" size={32}/><p className="text-[10px] font-black uppercase text-blue-600 tracking-tighter">{selectedFileName || "Select Document"}</p>
              </div>
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl uppercase italic tracking-widest">Confirm & Submit</button>
              <button type="button" onClick={() => setShowModal(false)} className="w-full bg-slate-100 text-slate-400 py-4 rounded-2xl font-black uppercase text-[10px] hover:bg-red-50 hover:text-red-500 transition tracking-widest">Discard Application</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
